#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int M; scanf("%d", &M);
        while (M--) {
            int L, R; scanf("%d %d", &L, &R);
            int len = R - L + 1;
            int *tmp = (int*)malloc(len * sizeof(int));
            for (int i = 0; i < len; ++i) tmp[i] = A[L - 1 + i];
            qsort(tmp, len, sizeof(int), cmp);
            long long ans = 0;
            for (int i = 1; i < len; ++i) {
                long long d = (long long)tmp[i] - tmp[i-1];
                ans += d * d;
            }
            printf("%lld\n", ans);
            free(tmp);
        }
        free(A);
    }
    return 0;
}

