for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const A = data.slice(idx, idx + N);
  idx += N;
  const M = data[idx++];
  for (let q = 0; q < M; q++) {
    const L = data[idx++];
    const R = data[idx++];
    const sub = A.slice(L - 1, R);
    sub.sort((a, b) => a - b);
    let sum = 0;
    for (let i = 1; i < sub.length; i++) {
      const d = sub[i] - sub[i - 1];
      sum += d * d;
    }
    out.push(String(sum));
  }
}
